@Test public void unescapeUnknownEntity() {
        String escaped = "&unknownEntity; &validAmp;";
        String result = Entities.unescape(escaped);
        assertEquals("&unknownEntity; &", result);
    }

@Test public void unescapeOutOfRangeNumeric() {
        String escaped = "&#x10000; &#65537; &#160;";
        String result = Entities.unescape(escaped);
        assertEquals("&#x10000; &#65537;  ", result);
    }

@Test public void unescapeMixedValidInvalid() {
        String escaped = "&lt; &NOTAREALENTITY &gt; &#65;";
        String result = Entities.unescape(escaped);
        assertEquals("< &NOTAREALENTITY > A", result);
    }
